def test_error_mapping() -> None:
    err = SolvaPayError('boom')
    setattr(err, 'status', 400)
    setattr(err, 'code', 'bad_request')
    assert getattr(err, 'status') == 400
    assert getattr(err, 'code') == 'bad_request'
